#include <stdio.h>
int main(){
    int T;
    scanf("%d", &T);
    while(T--){
        char J[105], S[105];
        scanf("%s", J);
        scanf("%s", S);
        int isJewel[128] = {0};
        for(int i = 0; J[i]; i++) isJewel[(int)J[i]] = 1;
        int cnt = 0;
        for(int i = 0; S[i]; i++) if(isJewel[(int)S[i]]) cnt++;
        printf("%d\n", cnt);
    }
    return 0;
}

